from typing import List, AsyncIterator
from token_utils import TokenManager
from llm_client import LLMClient, LLMConfig
import asyncio
import os

class DocumentProcessor:
    """Map-Reduce 模式处理超长文档"""

    def __init__(self, token_manager, llm_client):
        self.token_manager = token_manager
        self.llm_client = llm_client

    def chunk_text(self, text: str, chunk_size: int = 4000, overlap: int = 200) -> List[str]:
        """按 token 大小分块，带有重叠"""
        tokens = self.token_manager.encoder.encode(text)
        print(f"文本 Total tokens: {len(tokens)}")
        chunks = []
        start = 0
        while start < len(tokens):
            end = min(start + chunk_size, len(tokens))
            chunk_tokens = tokens[start:end]
            chunks.append(self.token_manager.encoder.decode(chunk_tokens))
            start += chunk_size - overlap  # 保持重叠
        return chunks
    
    async def map_summarize(self, chunks: List[str]) -> List[str]:
        """对每个块进行独立总结"""
        async def summarize_chunk(chunk: str) -> str:
            response = await self.llm_client.chat([
                {"role": "user", "content": f"请总结以下内容：{chunk}"}
            ])
            return response["choices"][0]["message"]["content"]
        
        return await asyncio.gather(*(summarize_chunk(chunk) for chunk in chunks))
    
    async def reduce_summarize(self, summaries: List[str]) -> str:
        """将多个摘要合并为最终摘要"""
        combinded = "\n---\n".join(summaries)
        response = await self.llm_client.chat([
            {"role": "user", "content": f"请将以下摘要合并成一个更简洁的摘要：{combinded}"}
        ])
        return response["choices"][0]["message"]["content"]
    

